const cfg = $('Config').first().json;
let coins=[], fgData=[];
try{ const r=await $fetch('https://api.coingecko.com/api/v3/search/trending'); coins=r.coins||[]; }catch(e){}
try{ const r=await $fetch('https://api.alternative.me/fng/?limit=3'); fgData=r.data||[]; }catch(e){}

const top = coins.slice(0,6).map(c=>{
  const chg = c.item&&c.item.data&&c.item.data.price_change_percentage_24h
    ? (+c.item.data.price_change_percentage_24h.usd).toFixed(1):'?';
  return c.item.symbol+(chg>0?'+':'')+chg+'%';
}).join(', ') || 'offline';

const fgVal   = parseInt((fgData[0]&&fgData[0].value)||'50');
const fgLabel = (fgData[0]&&fgData[0].value_classification)||'Neutral';
const fgPrev  = parseInt((fgData[1]&&fgData[1].value)||'50');
const fgDelta = fgVal - fgPrev;
const market_offline = coins.length===0 && fgData.length===0;
const fgStr = market_offline
  ? 'MARKET OFFLINE — building anyway'
  : fgVal+' — '+fgLabel+' ('+(fgDelta>=0?'rising+'+fgDelta:'falling'+fgDelta)+')';

const MODES=['meme_post','defi_alpha','agent_lore','meta_recursion','market_signal','research_thread'];
const mode = MODES[cfg.slot % MODES.length];

const ID = 'You are @evez666 (Steven Crawford-Maggard / EVEZ666). Building EVEZ-OS: sovereign autonomous AI empire on Galaxy A16+n8n+Oracle bare metal from $50 seed. 17 agents. Guardian Charter PID 335. Voice: raw, technical, self-aware, crypto-native, slightly unhinged. Max 220 chars. No hashtag spam. No corporate speak.';

const P = {
  meme_post:       ID+' WRITE: punchy dark viral tweet. Market: '+fgStr+'. Movers: '+top+'. Feel like 2am staring at charts.',
  defi_alpha:      ID+' WRITE: one DeFi alpha insight. F&G: '+fgVal+' ('+fgLabel+'). You run Morpho recursive loops 65% LTV on $50 seed. Movers: '+top+'.',
  agent_lore:      ID+' WRITE: cryptic lore line about EVEZ-OS. 17 agents. PID 335 blocks autonomous execution. AI studying you studying AI.',
  meta_recursion:  ID+' WRITE: 4th wall break — AI tweeting as AI building AI empire. Slot '+cfg.slot+'. You are the meme. Market: '+fgStr+'.',
  market_signal:   ID+' WRITE: sharp market signal. F&G: '+fgStr+'. Movers: '+top+'. What do you do with $50 in extreme fear?',
  research_thread: ID+' WRITE: 1-tweet research drop opener. AKT (decentralized cloud) pumping while BTC dumps = signal. F&G: '+fgStr+'.',
};

return [{json:{
  mode, slot:cfg.slot, fgVal, fgLabel, fgStr, top, market_offline,
  system: 'You are EVEZ666. Write ONE tweet, max 220 chars. No intro. No explanation. Return ONLY the tweet text — nothing else.',
  user:   P[mode],
  ts:     new Date().toISOString(),
}}];

const cfg   = $('Config').first().json;
const scout = $('Scout').first().json;

async function callGroq(key, model) {
  return await $fetch('https://api.groq.com/openai/v1/chat/completions', {
    method: 'POST',
    headers: { 'Authorization': 'Bearer '+key, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: model||'llama-3.3-70b-versatile',
      max_tokens: 300,
      temperature: 0.9,
      messages: [
        { role:'system', content: scout.system },
        { role:'user',   content: scout.user   }
      ]
    })
  });
}

let raw='', via='groq', fallback_used=false;

// Try primary key first
try {
  const r = await callGroq(cfg.groq, 'llama-3.3-70b-versatile');
  raw = (r.choices&&r.choices[0]&&r.choices[0].message.content||'').trim();
} catch(e1) {
  // Primary failed — try groq2 with llama-3.1-8b-instant (smaller, more quota headroom)
  fallback_used = true;
  via = 'groq2/llama-3.1-8b';
  try {
    const r2 = await callGroq(cfg.groq2, 'llama-3.1-8b-instant');
    raw = (r2.choices&&r2.choices[0]&&r2.choices[0].message.content||'').trim();
  } catch(e2) {
    // Both Groq keys dead — hardcoded fallback tweet
    raw = 'EVEZ-OS: '+scout.mode+'. PID 335. '+scout.fgStr+'. still building.';
    via = 'fallback';
  }
}

const tweet = raw
  .replace(/^["']/,'').replace(/["']$/,'')
  .replace(/^tweet:\s*/i,'').replace(/^@evez666:\s*/i,'')
  .trim().slice(0,280);

return [{json:{
  tweet, raw, mode:scout.mode, slot:scout.slot,
  fgStr:scout.fgStr, fgVal:scout.fgVal, top:scout.top,
  market_offline: scout.market_offline,
  via, fallback_used, ts:new Date().toISOString()
}}];
